269		if err != nil {
270			return nil, fmt.Errorf("review session: read manifest: %w", err)
271		}
272		var manifest reviewSessionManifest
273		if err := json.Unmarshal(data, &manifest); err != nil {
274			return nil, fmt.Errorf("review session: parse manifest: %w", err)
275		}
276		session := &ReviewSession{
277			ID:             manifest.ID,
278			ArtifactID:     manifest.ArtifactID,
279			ArtifactSHA:    manifest.ArtifactSHA,
280			ArtifactGitRev: manifest.ArtifactGitRev,
281			SystemRubric:   manifest.SystemRubric,
282			TemplateRef:    manifest.TemplateRef,
283			PromptRef:      manifest.PromptRef,
284			Status:         manifest.Status,
285			CostUSD:        manifest.CostUSD,
286			MaxBillableUSD: manifest.MaxBillableUSD,
287		}
288	
289		turnsPath := filepath.Join(root, reviewTurnsName)
290		f, err := os.Open(turnsPath)
291		if err != nil {
292			if os.IsNotExist(err) {
293				return session, nil
294			}
295			return nil, fmt.Errorf("review session: read turns: %w", err)
296		}
297		defer f.Close()
298	
299		scanner := bufio.NewScanner(f)
300		scanner.Buffer(make([]byte, 0, 64*1024), 8*1024*1024)
301		for scanner.Scan() {
302			line := strings.TrimSpace(scanner.Text())
303			if line == "" {
304				continue
305			}
306			var turn ReviewTurn
307			if err := json.Unmarshal([]byte(line), &turn); err != nil {
308				return nil, fmt.Errorf("review session: parse turn: %w", err)
309			}
310			session.Turns = append(session.Turns, turn)
311		}
312		if err := scanner.Err(); err != nil {
313			return nil, fmt.Errorf("review session: scan turns: %w", err)
314		}
315		return session, nil
316	}
