318	func (s *ReviewSessionStore) sessionRoot(sessionID string) (string, error) {
319		if s == nil {
320			return "", errors.New("review session store: nil store")
321		}
322		if s.projectRoot == "" {
323			return "", errors.New("review session store: empty project root")
324		}
325		if sessionID == "" {
326			return "", errors.New("review session store: empty session id")
327		}
328		if sessionID == "." || sessionID == ".." || strings.ContainsAny(sessionID, "/\\") {
329			return "", fmt.Errorf("review session store: invalid session id %q", sessionID)
330		}
331		return ddxroot.JoinProject(s.projectRoot, reviewSessionsDirName, sessionID), nil
332	}
